/**
 * AllProjects - Page listant tous les projets
 * @description Affiche une grille de projets avec des aperçus vidéo au survol et des liens vers les démos et les codes sources.
 * @component Client
 */
export default function AllProjects() {
    const [activeVideo, setActiveVideo] = useState<string | null>(null);
    const [hoveredProject, setHoveredProject] = useState<number | null>(null);

    const projectCards = useMemo(() => projects, []);

    return (
        <main className="min-h-screen bg-[#f4f1ea] text-[#1f1d1f]">
            <section className="w-full px-5 md:px-[3vw] py-10 md:py-16">
                <Title title="Projects" />
                <div className="mt-10 grid gap-5 sm:grid-cols-2 xl:grid-cols-4">
                    {projectCards.map((project) => (
                        <article
                            key={project.id}
                            onMouseEnter={() => setHoveredProject(project.id)}
                            onMouseLeave={() => setHoveredProject(null)}
                            className="group relative overflow-hidden rounded-[28px] border border-[#1f1d1f]/15 bg-white/70 shadow-[0_18px_50px_rgba(0,0,0,0.08)] backdrop-blur-sm transition-transform duration-300 hover:-translate-y-1"
                        >
                            <div className="relative aspect-[4/5] overflow-hidden">
                                <img
                                    src={project.image}
                                    alt={project.title}
                                    className="h-full w-full object-cover transition-transform duration-700 group-hover:scale-105"
                                />
                                <div className="absolute inset-0 bg-gradient-to-t from-[#0f0f10]/90 via-[#0f0f10]/20 to-transparent" />
                                <div className="absolute inset-x-0 bottom-0 p-5 text-white">
                                    <div className="mb-3 flex flex-wrap gap-2">
                                        {project.tags.map((tag) => (
                                            <span
                                                key={tag}
                                                className="rounded-full border border-white/30 bg-white/10 px-3 py-1 text-[11px] font-medium uppercase tracking-[0.18em]"
                                            >
                                                {tag}
                                            </span>
                                        ))}
                                    </div>
                                    <h3 className="text-2xl font-bold leading-tight">{project.title}</h3>
                                    <p className="mt-2 max-w-xs text-sm text-white/80">{project.description}</p>
                                    <div className="mt-4 flex items-center gap-3">
                                        {project.demoLink && project.demoLink !== "#" && (
                                            <a
                                                href={project.demoLink}
                                                className="inline-flex items-center gap-2 rounded-full bg-white px-4 py-2 text-sm font-semibold text-[#1f1d1f] transition-transform hover:scale-[1.02]"
                                            >
                                                Voir
                                                <Play className="h-4 w-4" />
                                            </a>
                                        )}
                                        {project.repoLink && project.repoLink !== "#" && (
                                            <a
                                                href={project.repoLink}
                                                className="inline-flex items-center gap-2 rounded-full border border-white/30 bg-white/10 px-4 py-2 text-sm font-semibold text-white transition-colors hover:bg-white/20"
                                            >
                                                Code
                                                <Github className="h-4 w-4" />
                                            </a>
                                        )}
                                    </div>
                                </div>
                            </div>

                            {project.hoverVideo && hoveredProject === project.id && (
                                <button
                                    type="button"
                                    onClick={() => setActiveVideo(project.hoverVideo ?? null)}
                                    className="absolute right-4 top-4 rounded-full bg-[#1f1d1f] px-4 py-2 text-xs font-semibold uppercase tracking-[0.18em] text-white shadow-lg"
                                >
                                    Preview
                                </button>
                            )}
                        </article>
                    ))}
                </div>
            </section>

            {activeVideo && (
                <div
                    role="dialog"
                    aria-modal="true"
                    className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 p-4"
                    onClick={() => setActiveVideo(null)}
                >
                    <div className="relative w-full max-w-5xl overflow-hidden rounded-[24px] bg-black shadow-2xl" onClick={(event) => event.stopPropagation()}>
                        <button
                            type="button"
                            onClick={() => setActiveVideo(null)}
                            className="absolute right-4 top-4 z-10 rounded-full bg-white/10 px-4 py-2 text-sm font-semibold text-white backdrop-blur"
                        >
                            Fermer
                        </button>
                        <video className="h-full w-full object-cover" src={activeVideo} autoPlay muted loop playsInline controls />
                    </div>
                </div>
            )}
        </main>
    );
}
